def save_upload(f, suffix=""):
    tmp = tempfile.NamedTemporaryFile(delete=False, suffix=suffix)
    tmp.write(f.read()); tmp.flush()
    return tmp.name

def to_excel_bytes(df):
    buf = io.BytesIO()
    with pd.ExcelWriter(buf, engine="openpyxl") as w:
        df.to_excel(w, index=False, sheet_name="Audience")
    return buf.getvalue()

def style_fn(styler, col, fn):
    m = "map" if hasattr(styler, "map") else "applymap"
    return getattr(styler, m)(fn, subset=[col])

